<?php $resumo = $resumo ?? []; ?>
<div class="page-header page-header-modern"><div><span class="breadcrumb">Cadastro Emergencial &gt; Catálogo</span><h1>Tipos de ajuda humanitária</h1><p>Consulta integrada aos materiais cadastrados no Sistema Cadastro Emergencial.</p></div></div>
<section class="compdec-overview-grid"><div><span>Tipos cadastrados</span><strong><?= e((int) ($resumo['total'] ?? 0)); ?></strong></div><div><span>Ativos</span><strong><?= e((int) ($resumo['ativos'] ?? 0)); ?></strong></div><div><span>Inativos</span><strong><?= e((int) ($resumo['inativos'] ?? 0)); ?></strong></div><div><span>Unidades de medida</span><strong><?= e((int) ($resumo['unidades'] ?? 0)); ?></strong></div></section>
<form method="get" action="<?= e(url('/tipos-ajuda')); ?>" class="compdec-filter-panel"><div class="field compdec-filter-search"><label>Busca inteligente</label><input name="busca" value="<?= e($filtros['busca']); ?>" placeholder="Material ou unidade de medida"></div><div class="field"><label>Status</label><select name="status"><option value="">Todos</option><option value="ativo" <?= $filtros['status'] === 'ativo' ? 'selected' : ''; ?>>Ativo</option><option value="inativo" <?= $filtros['status'] === 'inativo' ? 'selected' : ''; ?>>Inativo</option></select></div><div class="field"><label>Unidade</label><select name="unidade"><option value="">Todas</option><?php foreach ($unidades as $item): ?><option value="<?= e($item['unidade_medida']); ?>" <?= $filtros['unidade'] === $item['unidade_medida'] ? 'selected' : ''; ?>><?= e($item['unidade_medida']); ?></option><?php endforeach; ?></select></div><div class="compdec-filter-actions"><button class="button button-primary">Filtrar</button><a class="button button-light" href="<?= e(url('/tipos-ajuda')); ?>">Limpar</a></div></form>
<section class="compdec-card-list"><?php foreach ($tipos as $tipo): $ativo = (int) $tipo['ativo'] === 1; ?><article class="compdec-card"><header class="compdec-card-header"><div><span class="status-badge <?= $ativo ? 'badge-success' : 'badge-muted'; ?>"><?= $ativo ? 'Ativo' : 'Inativo'; ?></span><h2><?= e($tipo['nome']); ?></h2><p><?= $ativo ? 'Disponível para novas entregas no Cadastro Emergencial.' : 'Indisponível para novas entregas.'; ?></p></div></header><div class="compdec-card-grid"><div><span>Unidade de medida</span><strong><?= e($tipo['unidade_medida']); ?></strong></div><div><span>Cadastrado em</span><strong><?= e(date('d/m/Y H:i', strtotime((string) $tipo['criado_em']))); ?></strong></div><div><span>Origem</span><strong>Cadastro Emergencial</strong></div></div></article><?php endforeach; ?><?php if ($tipos === []): ?><div class="compdec-empty-state"><div><strong>Nenhum tipo de ajuda encontrado</strong><p>Revise os filtros ou verifique os registros no Cadastro Emergencial.</p></div></div><?php endif; ?></section>
